def _save_model(model: tf.keras.Model, labels: List[str], image_size: int) -> None:
    model_path = MODEL_DIR / "saved_model"
    labels_path = MODEL_DIR / "labels.json"
    if model_path.exists():
        shutil.rmtree(model_path, ignore_errors=True)
    model.save(str(model_path), include_optimizer=False)
    labels_path.write_text(json.dumps(labels, indent=2))
    model_state["model"] = model
    model_state["labels"] = labels
    model_state["num_classes"] = len(labels)
    model_state["image_size"] = (image_size, image_size)
    try:
        model_state["input_shape"] = model.input_shape
    except Exception:
        model_state["input_shape"] = None
    meta = _metadata()
    meta["model_updated_at"] = _now()
    meta["labels"] = labels
    meta["image_size"] = image_size
    _save_metadata(meta)


def _build_image_model(num_classes: int, image_size: int, learning_rate: float, fine_tune: bool) -> tf.keras.Model:
    inputs = tf.keras.Input(shape=(image_size, image_size, 3))
    base = tf.keras.applications.MobileNetV2(
        include_top=False,
        weights="imagenet",
        input_tensor=inputs,
        pooling="avg",
    )
    base.trainable = fine_tune
    x = tf.keras.layers.Dropout(0.2)(base.output)
    outputs = tf.keras.layers.Dense(num_classes, activation="softmax")(x)
    model = tf.keras.Model(inputs=inputs, outputs=outputs)
    opt = tf.keras.optimizers.Adam(learning_rate=learning_rate)
    model.compile(optimizer=opt, loss="sparse_categorical_crossentropy", metrics=["accuracy"])
    return model


def _preprocess_image_bytes(image_bytes: bytes, image_size: int) -> np.ndarray:
    img = Image.open(io.BytesIO(image_bytes)).convert("RGB")
    img = img.resize((image_size, image_size))
    arr = np.asarray(img).astype(np.float32)
    arr = tf.keras.applications.mobilenet_v2.preprocess_input(arr)
    return arr


def _load_image_dataset(image_root: Path, image_size: int, max_samples: Optional[int] = None) -> Tuple[np.ndarray, np.ndarray, List[str]]:
    class_dirs = [p for p in image_root.iterdir() if p.is_dir()]
    labels = sorted([p.name for p in class_dirs])
    if not labels:
        raise ValueError("No labeled image classes found")
    xs: List[np.ndarray] = []
    ys: List[int] = []
    count = 0
    for label_idx, label in enumerate(labels):
        class_dir = image_root / label
        for fp in sorted(class_dir.iterdir()):
            if fp.is_file():
                try:
                    xs.append(_preprocess_image_bytes(fp.read_bytes(), image_size))
                    ys.append(label_idx)
                    count += 1
                    if max_samples is not None and count >= max_samples:
                        break
                except Exception:
                    continue
        if max_samples is not None and count >= max_samples:
            break
    if not xs:
        raise ValueError("No valid images found")
    x = np.stack(xs, axis=0)
    y = np.asarray(ys, dtype=np.int32)
    return x, y, labels


def _load_csv_dataset(csv_dir: Path) -> Tuple[np.ndarray, np.ndarray, List[str]]:
    if pd is None:
        raise RuntimeError("pandas is required for CSV training")
    csv_files = sorted(csv_dir.glob("*.csv"))
    if not csv_files:
        raise ValueError("No CSV files found")
    dfs = []
    for fp in csv_files:
        try:
            dfs.append(pd.read_csv(fp))
        except Exception:
            continue
    if not dfs:
        raise ValueError("No readable CSV files found")
    df = pd.concat(dfs, ignore_index=True)
    if "label" not in df.columns:
        raise ValueError("CSV must include a 'label' column")
    df = df.dropna(subset=["label"])
    labels = sorted(df["label"].astype(str).unique().tolist())
    if len(labels) < 2:
        raise ValueError("Need at least 2 classes to train")
    y = df["label"].astype(str).map({lab: i for i, lab in enumerate(labels)}).to_numpy(dtype=np.int32)
    X = df.drop(columns=["label"])
    X = X.select_dtypes(include=[np.number]).fillna(0.0)
    if X.shape[1] == 0:
        raise ValueError("CSV has no numeric feature columns")
    x = X.to_numpy(dtype=np.float32)
    x = (x - np.mean(x, axis=0, keepdims=True)) / (np.std(x, axis=0, keepdims=True) + 1e-8)
    return x, y, labels


def _train_image_model(config: TrainConfig) -> Dict[str, Any]:
    x, y, labels = _load_image_dataset(IMAGE_DIR, config.image_size, config.max_samples)
    idx = np.arange(len(x))
    np.random.shuffle(idx)
    x, y = x[idx], y[idx]
    split = int(len(x) * (1.0 - config.validation_split))
    split = max(1, min(split, len(x) - 1))
    x_train, y_train = x[:split], y[:split]
    x_val, y_val = x[split:], y[split:]
    model = _build_image_model(len(labels), config.image_size, config.learning_rate, config.fine_tune)
    callbacks = [
        tf.keras.callbacks.EarlyStopping(monitor="val_accuracy", patience=3, restore_best_weights=True),
        tf.keras.callbacks.ModelCheckpoint(filepath=str(MODEL_DIR / "checkpoint.keras"), save_best_only=True, monitor="val_accuracy"),
    ]
    history = model.fit(
        x_train,
        y_train,
        validation_data=(x_val, y_val) if len(x_val) else None,
        epochs=config.epochs,
        batch_size=config.batch_size,
        callbacks=callbacks,
        verbose=0,
    )
    _save_model(model, labels, config.image_size)
    return {
        "history": history.history,
        "labels": labels,
        "samples": int(len(x)),
        "validation_samples": int(len(x_val)),
    }


def _train_csv_model(config: TrainConfig) -> Dict[str, Any]:
    x, y, labels = _load_csv_dataset(CSV_DIR)
    if config.max_samples is not None and len(x) > config.max_samples:
        x = x[: config.max_samples]
        y = y[: config.max_samples]
    idx = np.arange(len(x))
    np.random.shuffle(idx)
    x, y = x[idx], y[idx]
    split = int(len(x) * (1.0 - config.validation_split))
    split = max(1, min(split, len(x) - 1))
    x_train, y_train = x[:split], y[:split]
    x_val, y_val = x[split:], y[split:]
    model = tf.keras.Sequential(
        [
            tf.keras.layers.Input(shape=(x.shape[1],)),
            tf.keras.layers.Dense(128, activation="relu"),
            tf.keras.layers.Dropout(0.2),
            tf.keras.layers.Dense(64, activation="relu"),
            tf.keras.layers.Dense(len(labels), activation="softmax"),
        ]
    )
    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=config.learning_rate),
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"],
    )
    callbacks = [
        tf.keras.callbacks.EarlyStopping(monitor="val_accuracy", patience=3, restore_best_weights=True),
        tf.keras.callbacks.ModelCheckpoint(filepath=str(MODEL_DIR / "checkpoint.keras"), save_best_only=True, monitor="val_accuracy"),
    ]
    history = model.fit(
        x_train,
        y_train,
        validation_data=(x_val, y_val) if len(x_val) else None,
        epochs=config.epochs,
        batch_size=config.batch_size,
        callbacks=callbacks,
        verbose=0,
    )
    _save_model(model, labels, image_size=0)
    return {
        "history": history.history,
        "labels": labels,
        "samples": int(len(x)),
        "validation_samples": int(len(x_val)),
    }


def _train_async(config: TrainConfig, data_kind: str) -> None:
    with train_lock:
        train_status["running"] = True
        train_status["started_at"] = _now()
        train_status["finished_at"] = None
        train_status["message"] = f"training {data_kind}"
        train_status["last_error"] = None
        train_status["epoch"] = None
        train_status["history"] = None
    try:
        if data_kind == "image":
            result = _train_image_model(config)
        elif data_kind == "csv":
            result = _train_csv_model(config)
        else:
            raise ValueError("Unsupported data kind")
        with train_lock:
            train_status["running"] = False
            train_status["finished_at"] = _now()
            train_status["message"] = "training complete"
            train_status["history"] = result["history"]
    except Exception as e:
        with train_lock:
            train_status["running"] = False
            train_status["finished_at"] = _now()
            train_status["message"] = "training failed"
            train_status["last_error"] = str(e)


