class PredictImageRequest(BaseModel):
    image_base64: str


@app.post("/predict/image", response_model=PredictResponse)
def predict_image(req: PredictImageRequest) -> PredictResponse:
    _ensure_model_loaded()
    if model_state["model"] is None:
        raise HTTPException(status_code=404, detail="Model not trained or not loaded")
    try:
        image_bytes = base64.b64decode(req.image_base64)
        x = _preprocess_image_bytes(image_bytes, int(model_state["image_size"][0]))
        preds = model_state["model"].predict(np.expand_dims(x, axis=0), verbose=0)[0]
        idx = int(np.argmax(preds))
        labels = model_state["labels"]
        probabilities = {labels[i]: float(preds[i]) for i in range(len(labels))}
        return PredictResponse(
            predicted_label=labels[idx],
            confidence=float(preds[idx]),
            probabilities=probabilities,
        )
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))


class PredictCsvRequest(BaseModel):
    features: Dict[str, float]


@app.post("/predict/csv")
def predict_csv(req: PredictCsvRequest) -> Dict[str, Any]:
    _ensure_model_loaded()
    if model_state["model"] is None:
        raise HTTPException(status_code=404, detail="Model not trained or not loaded")
    if not isinstance(model_state["model"], tf.keras.Model):
        raise HTTPException(status_code=400, detail="Current model is not a CSV model")
    try:
        labels = model_state["labels"]
        feature_values = np.array([float(v) for v in req.features.values()], dtype=np.float32).reshape(1, -1)
        preds = model_state["model"].predict(feature_values, verbose=0)[0]
        idx = int(np.argmax(preds))
        return {
            "predicted_label": labels[idx],
            "confidence": float(preds[idx]),
            "probabilities": {labels[i]: float(preds[i]) for i in range(len(labels))},
        }
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))


