@app.post("/model/reset")
def reset_model() -> Dict[str, Any]:
    if MODEL_DIR.exists():
        shutil.rmtree(MODEL_DIR, ignore_errors=True)
        MODEL_DIR.mkdir(parents=True, exist_ok=True)
    model_state["model"] = None
    model_state["labels"] = []
    model_state["input_shape"] = None
    model_state["num_classes"] = None
    meta = _metadata()
    meta["model_reset_at"] = _now()
    _save_metadata(meta)
    return {"status": "ok"}


